// Allowlist: only your chat ID may use this bot.
// Edit ALLOWED_CHAT_ID below after you find your chat ID.
const ALLOWED_CHAT_ID = 0; // <-- PASTE YOUR CHAT ID HERE

const chatId = $input.first().json.message?.chat?.id;
const text = ($input.first().json.message?.text || '').trim();

if (ALLOWED_CHAT_ID === 0) {
  // Bootstrap mode: allow anything so you can discover your chat ID
  return [{ json: { chat_id: chatId, text, command: text.startsWith('/') ? text.split(' ')[0] : '', bootstrap_mode: true } }];
}

if (chatId !== ALLOWED_CHAT_ID) {
  return []; // silently drop
}

return [{ json: { chat_id: chatId, text, command: text.startsWith('/') ? text.split(' ')[0] : '', bootstrap_mode: false } }];

// Merge incoming message + session into a single workflow context object.
const incoming = $('Authz + Parse').first().json;
const session = $input.first().json;

const state = session?.state || 'idle';
const entry_id = session?.entry_id || null;
const raw_transcript = session?.raw_transcript || '';
const turn_count = session?.turn_count || 0;

// Decide route
let route;
if (incoming.command === '/start') route = 'start';
else if (incoming.command === '/journal') route = 'open_entry';
else if (incoming.command === '/cancel') route = 'cancel';
else if (state === 'awaiting_intake') route = 'append_intake';
else route = 'idle_fallback';

return [{
  json: {
    chat_id: incoming.chat_id,
    text: incoming.text,
    command: incoming.command,
    state,
    entry_id,
    raw_transcript,
    turn_count,
    route
  }
}];

