// Parse + validate the reflection JSON. If invalid, store raw and surface a graceful fallback.
const resp = $input.first().json;
let text = resp.content?.[0]?.text || '';
const inputTokens = resp.usage?.input_tokens || 0;
const outputTokens = resp.usage?.output_tokens || 0;

// Defensive: strip code fences if Sonnet ever ignores instructions
text = text.trim().replace(/^```(?:json)?/i, '').replace(/```$/, '').trim();

let parsed = null;
let parseError = null;
try {
  parsed = JSON.parse(text);
} catch (e) {
  parseError = e.message;
}

const loadJson = $('Load Reflect Prompt').first().json;

// Build the user-facing message (Markdown for Telegram)
let userMsg;
if (parsed && parsed.stress_present === false) {
  userMsg = `*Reflection — ${new Date().toISOString().slice(0,10)}*\n\nNo significant stress today. Logged.\n\n_${parsed.one_observation || 'Steady day.'}_`;
} else if (parsed && parsed.rumination_flag) {
  userMsg = `*Reflection — ${new Date().toISOString().slice(0,10)}*\n\n⚠️ Recurring theme detected. Not re-analysing tonight.\n\n_${parsed.one_question}_`;
} else if (parsed && parsed.thought_record) {
  const tr = parsed.thought_record;
  const distortions = (tr.cognitive_distortions || []).join(', ') || 'none flagged';
  userMsg = `*Reflection — ${new Date().toISOString().slice(0,10)}*\n\n` +
    `*Stress level:* ${parsed.stress_level ?? 'n/a'}/10\n` +
    `*Situation:* ${tr.situation}\n` +
    `*Automatic thought:* "${tr.automatic_thought}"\n` +
    `*Emotion:* ${tr.emotion} (${tr.emotion_intensity}/10)\n` +
    `*Distortions:* ${distortions}\n` +
    `*Evidence for:* ${tr.evidence_for}\n` +
    `*Evidence against:* ${tr.evidence_against}\n` +
    `*Balanced thought:* ${tr.balanced_thought}\n` +
    `*Projected emotion intensity:* ${tr.projected_emotion_intensity}/10\n` +
    `*Controllability:* ${parsed.controllability || 'n/a'}\n\n` +
    `*Observation:* ${parsed.one_observation}\n` +
    `*To sit with:* _${parsed.one_question}_`;
} else {
  userMsg = `*Reflection saved.*\n\n(I had trouble producing a structured thought record — the raw transcript is preserved in your archive.)`;
}

return [{
  json: {
    chat_id: loadJson.chat_id,
    entry_id: loadJson.entry_id,
    transcript: loadJson.transcript,
    parsed,
    parse_error: parseError,
    raw_output: text,
    user_message: userMsg,
    input_tokens: inputTokens,
    output_tokens: outputTokens
  }
}];

