// Write a human-readable Markdown export to /files/archive/YYYY/MM/DD-<id>.md
const fs = require('fs');
const path = require('path');

const pj = $('Parse Reflection').first().json;
const now = new Date();
const yyyy = now.getFullYear();
const mm = String(now.getMonth() + 1).padStart(2, '0');
const dd = String(now.getDate()).padStart(2, '0');
const dir = `/files/archive/${yyyy}/${mm}`;
fs.mkdirSync(dir, { recursive: true });
const file = `${dir}/${dd}-entry-${pj.entry_id}.md`;

const tr = pj.parsed?.thought_record;
const distortions = (tr?.cognitive_distortions || []).join(', ') || 'none flagged';

const md = [
  `# Journal — ${yyyy}-${mm}-${dd} (entry #${pj.entry_id})`,
  '',
  '## Transcript',
  '',
  '```',
  pj.transcript || '',
  '```',
  '',
  '## Stress Reflection',
  '',
  pj.parsed ? (
    pj.parsed.stress_present === false
      ? `_No significant stress today._\n\n**Observation:** ${pj.parsed.one_observation}\n\n**To sit with:** ${pj.parsed.one_question}`
      : pj.parsed.rumination_flag
        ? `**⚠ Rumination flagged.** Theme is recurring; tonight's entry is not being re-analysed.\n\n**To sit with:** ${pj.parsed.one_question}`
        : tr ? [
            `**Stress level:** ${pj.parsed.stress_level ?? 'n/a'}/10`,
            `**Situation:** ${tr.situation}`,
            `**Automatic thought:** "${tr.automatic_thought}"`,
            `**Emotion:** ${tr.emotion} (${tr.emotion_intensity}/10)`,
            `**Distortions:** ${distortions}`,
            `**Evidence for:** ${tr.evidence_for}`,
            `**Evidence against:** ${tr.evidence_against}`,
            `**Balanced thought:** ${tr.balanced_thought}`,
            `**Projected emotion intensity:** ${tr.projected_emotion_intensity}/10`,
            `**Controllability:** ${pj.parsed.controllability || 'n/a'}`,
            '',
            `**Observation:** ${pj.parsed.one_observation}`,
            `**To sit with:** ${pj.parsed.one_question}`,
          ].join('\n') : '_(no thought record produced)_'
  ) : `_Reflection failed to parse. Raw output preserved in DB._\n\nParse error: ${pj.parse_error}`,
  '',
  '---',
  `_Generated by Mirror at ${now.toISOString()}_`
].join('\n');

fs.writeFileSync(file, md, 'utf8');

return [{ json: { ...pj, archive_path: file } }];

